            return ir::ModifierFlags::PROTECTED;
        }

        return ir::ModifierFlags::PUBLIC;
    };
    if (((overLoadAliasFlags ^ overloadedMethodFlags) & (ir::ModifierFlags::STATIC | ir::ModifierFlags::ASYNC)) != 0) {
        checker->LogError(diagnostic::OVERLOAD_SAME_ACCESS_MODIFIERS_STATIC_ASYNC, {}, pos);
        return false;
    }

    if (((overLoadAliasFlags ^ overloadedMethodFlags) & (ir::ModifierFlags::CONSTRUCTOR)) != 0) {
        checker->LogError(diagnostic::OVERLOAD_MUST_BOTH_CONSTRUCT, {}, pos);
        return false;
    }

    if ((overLoadAliasFlags & ir::ModifierFlags::EXPORT) != 0 &&
        (((overLoadAliasFlags ^ overloadedMethodFlags) & (ir::ModifierFlags::EXPORT)) != 0)) {
        checker->LogError(diagnostic::OVERLOAD_MUST_ALSO_BE_EXPORTED, {}, pos);
        return false;
    }
    auto overloadAccess = getAccessModifier(overLoadAliasFlags);
    auto methodAccess = getAccessModifier(overloadedMethodFlags);
    // An explicit overload is public but at least one overloaded method is not public.
    if (overloadAccess == ir::ModifierFlags::PUBLIC && methodAccess != ir::ModifierFlags::PUBLIC) {
        checker->LogError(diagnostic::OVERLOAD_SAME_ACCESS_MODIFIERS, {}, pos);
        return false;
    }

    // An explicit overload is protected but at least one overloaded method is private.
    if (overloadAccess == ir::ModifierFlags::PROTECTED && methodAccess == ir::ModifierFlags::PRIVATE) {
        checker->LogError(diagnostic::OVERLOAD_SAME_ACCESS_MODIFIERS, {}, pos);
        return false;
    }

    return true;
}

static bool CheckOverloadedName(ETSChecker *checker, ir::OverloadDeclaration *node, ir::Expression *overloadedName)
{
    if (overloadedName->Variable()->Declaration() == nullptr) {
        checker->LogError(diagnostic::OVERLOADED_NAME_MUST_FUNCTION, {}, overloadedName->Start());
        overloadedName->SetTsType(checker->GlobalTypeError());
        return false;
    }

    auto *identDeclNode = overloadedName->Variable()->Declaration()->Node();
    if (identDeclNode->IsImportSpecifier()) {
        auto *importedVar = identDeclNode->AsImportSpecifier()->Imported()->Variable();
        if (importedVar == nullptr || importedVar->Declaration() == nullptr) {
            checker->LogError(diagnostic::OVERLOADED_NAME_MUST_FUNCTION, {}, overloadedName->Start());
            overloadedName->SetTsType(checker->GlobalTypeError());
            return false;
        }
        identDeclNode = importedVar->Declaration()->Node();
    }

    if (!identDeclNode->IsMethodDefinition()) {
        checker->LogError(diagnostic::OVERLOADED_NAME_MUST_FUNCTION, {}, overloadedName->Start());
        overloadedName->SetTsType(checker->GlobalTypeError());
        return false;
    }

    if (!identDeclNode->AsMethodDefinition()->Overloads().empty() && !identDeclNode->IsConstructor()) {
        return false;
    }

    return CheckAccessModifierForOverloadDeclaration(checker, node->Modifiers(), identDeclNode->Modifiers(),
                                                     overloadedName->Start());
}

static bool ResolveFunctionOverloadIdentifier(ETSChecker *checker, ir::OverloadDeclaration *node,
                                              ir::Expression *overloadedName)
{
    auto *ident = overloadedName->AsIdentifier();
    auto *functionScope = node->Parent()->Scope();
    if (ident->Variable() == nullptr) {
        auto *identType = checker->ResolveIdentifier(ident->AsIdentifier());
        if (identType->IsTypeError()) {
            checker->LogError(diagnostic::OVERLOADED_NAME_MUST_FUNCTION, {}, ident->Start());
            ident->SetTsType(checker->GlobalTypeError());
            return false;
        }
    }

    auto *variable = ident->Variable();
    if (variable == nullptr) {
        checker->LogError(diagnostic::OVERLOADED_NAME_MUST_FUNCTION, {}, ident->Start());
        ident->SetTsType(checker->GlobalTypeError());
        return false;
    }

    ident->SetTsType(variable->TsType());
    ident->SetVariable(variable);

    varbinder::Scope *identScope =
        variable->Declaration() != nullptr ? variable->Declaration()->Node()->Parent()->Scope() : nullptr;
    if (functionScope != identScope) {
        checker->LogError(diagnostic::OVERLOADED_FUNCS_MUST_BE_IN_SAME_SCOPE, {}, overloadedName->Start());
    }
    return CheckOverloadedName(checker, node, overloadedName);
}

static std::unordered_set<util::StringView> CollectInstanceOverloadDeclsTransitive(
    ETSObjectType *classType, ir::OverloadDeclaration *currOverloadDecl)
{
    std::unordered_set<util::StringView> transitivePropNames;
    for (auto const t : classType->TransitiveSupertypes()) {
        for (auto const p : t->InstanceDecls()) {
            auto *node = p.second->Declaration()->Node();
            if (!node->IsOverloadDeclaration()) {
                continue;
            }
            auto *superOverloadDecl = node->AsOverloadDeclaration();
            if (!superOverloadDecl->Name().Is(currOverloadDecl->Name().Utf8())) {
                continue;
            }
            for (auto *id : superOverloadDecl->OverloadedList()) {
                transitivePropNames.insert(id->AsIdentifier()->Name());
            }
        }
    }
    return transitivePropNames;
}

static void CheckOverloadDeclInheritance(ETSChecker *checker, ir::OverloadDeclaration *currOverloadDecl,
                                         const std::unordered_set<util::StringView> &currOverloadDeclNames)
{
    ETSObjectType *objType = nullptr;
    if (currOverloadDecl->Parent()->IsClassDefinition()) {
        objType = currOverloadDecl->Parent()->AsClassDefinition()->TsType()->AsETSObjectType();
    } else if (currOverloadDecl->Parent()->Parent()->IsTSInterfaceDeclaration()) {
        objType = currOverloadDecl->Parent()->Parent()->AsTSInterfaceDeclaration()->TsType()->AsETSObjectType();
    } else {
        ES2PANDA_UNREACHABLE();
    }
    auto transitivePropNames = CollectInstanceOverloadDeclsTransitive(objType, currOverloadDecl);
    if (transitivePropNames.empty()) {
        return;
    }
    for (auto tp : transitivePropNames) {
        if (currOverloadDeclNames.find(tp) == currOverloadDeclNames.end()) {
            checker->LogError(diagnostic::OVERLOAD_NAME_NOT_LISTED,
                              {tp, currOverloadDecl->AsClassElement()->Key()->AsIdentifier()->Name()},
                              currOverloadDecl->Start());
        }
    }
}

void ETSChecker::CheckFunctionOverloadDeclaration(ETSChecker *checker, ir::OverloadDeclaration *node) const
{
    for (auto *overloadedName : node->OverloadedList()) {
        if (overloadedName->IsMemberExpression()) {
            overloadedName->Check(checker);
            auto *var = overloadedName->AsMemberExpression()->Property()->Variable();
            overloadedName->SetVariable(var);
            if (var != nullptr) {
                checker->LogError(diagnostic::OVERLOADED_FUNCS_MUST_BE_IN_SAME_SCOPE, {}, overloadedName->Start());
            }
            continue;
        }
        if (!overloadedName->IsIdentifier()) {
            overloadedName->SetTsType(checker->GlobalTypeError());
            continue;
        }
        // SUPPRESS_CSA_NEXTLINE(alpha.core.AllocatorETSCheckerHint)
        if (!ResolveFunctionOverloadIdentifier(checker, node, overloadedName)) {
            continue;
        }
    }
}

