interface HiddenBase {
    private foo(s: string): int {
        return 100
    }
}

interface Visible extends HiddenBase {
    bar(x: int): int {
        return x + 1
    }

    // Spec-valid: HiddenBase.foo is private and not accessible here,
    // so it must not force listing 'foo' in the overload set.
    overload foo { bar }
}

class C implements Visible {}

function main() {
    let i: Visible = new C()
    arktest.assertEQ(i.foo(41), 42)

    let c = new C()
    arktest.assertEQ(c.foo(41), 42)
    arktest.assertEQ(c.bar(41), 42)
}
```

**What it checks**
- `Visible` inherits a **private** same-named method `foo` from `HiddenBase`.
- `Visible` declares `overload foo { bar }`.
- This should be valid per spec, because the inherited private `foo` is not accessible in `Visible`.
- Current buggy code can falsely emit:
  - `ESE0397: Method with the same name as overload declaration 'foo', overloadlist must list this medhod.`

